#include<bits/stdc++.h>
using namespace std;
const int maxn=200;
int a[maxn][maxn];
int b[2*maxn][maxn][maxn];
int main(){
  int m,n;
  cin>>m>>n;
  for(int i=1;i<=m;i++)
    for(int j=1;j<=n;j++)
      cin>>a[i][j];
  memset(b,-1,sizeof(b));
  b[2][1][1]=0;
  for(int k=3;k<m+n;k++)
    for(int i=1;i<n;i++)
      for(int j=i+1;j<=n;j++){
        int s=b[k][i][j];
        if(b[k-1][i][j]>s)s=b[k-1][i][j];
        if(b[k-1][i-1][j]>s)s=b[k-1][i-1][j];
        if(b[k-1][i][j-1]>s)s=b[k-1][i][j-1];
        if(b[k-1][i-1][j-1]>s)s=b[k-1][i-1][j-1];
        if(s==-1)continue; 
        b[k][i][j]=s+a[k-i][i]+a[k-j][j];
      }
  cout<<b[m+n-1][n-1][n];
  return 0;
 }
